     1→//! Dev Bridge - Secure RPC bridge for browser-to-native communication
     2→//!
     3→//! This module provides a development-only WebSocket server that mirrors Tauri commands,
     4→//! allowing Playwright and other browser-based tools to interact with native features.
     5→//!
     6→//! SECURITY:
     7→//! - Only compiled in debug mode (#[cfg(debug_assertions)])
     8→//! - localhost-only binding (127.0.0.1)
     9→//! - Token-based authentication
    10→//! - Command allowlist (no arbitrary execution)
    11→
    12→#![cfg(debug_assertions)]
    13→
    14→use crate::pty::{PtyManager, ProcessInfo};
    15→use axum::{
    16→    extract::{
    17→        ws::{Message, WebSocket, WebSocketUpgrade},
    18→        Query, State,
    19→    },
    20→    http::StatusCode,
    21→    response::{IntoResponse, Response},
    22→    routing::get,
    23→    Router,
    24→};
    25→use futures_util::{SinkExt, StreamExt};
    26→use parking_lot::Mutex;
    27→use serde::{Deserialize, Serialize};
    28→use std::sync::Arc;
    29→use tokio::sync::broadcast;
    30→use tower_http::cors::{Any, CorsLayer};
    31→
    32→/// Default port for dev bridge server
    33→const DEFAULT_PORT: u16 = 9876;
    34→
    35→/// RPC Request format
    36→#[derive(Debug, Deserialize)]
    37→pub struct RpcRequest {
    38→    /// Unique request ID for response correlation
    39→    pub id: String,
    40→    /// Command name (e.g., "pty_spawn", "pty_write")
    41→    pub cmd: String,
    42→    /// Command arguments as JSON
    43→    #[serde(default)]
    44→    pub args: serde_json::Value,
    45→}
    46→
    47→/// RPC Response format
    48→#[derive(Debug, Serialize)]
    49→pub struct RpcResponse {
    50→    /// Request ID for correlation
    51→    pub id: String,
    52→    /// Success flag
    53→    pub success: bool,
    54→    /// Result data (if success)
    55→    #[serde(skip_serializing_if = "Option::is_none")]
    56→    pub result: Option<serde_json::Value>,
    57→    /// Error message (if failure)
    58→    #[serde(skip_serializing_if = "Option::is_none")]
    59→    pub error: Option<String>,
    60→}
    61→
    62→/// Event broadcast to clients
    63→#[derive(Debug, Clone, Serialize)]
    64→pub struct RpcEvent {
    65→    /// Event type (e.g., "pty-output", "pty-exit")
    66→    pub event: String,
    67→    /// Event payload
    68→    pub payload: serde_json::Value,
    69→}
    70→
    71→/// Query params for auth
    72→#[derive(Debug, Deserialize)]
    73→pub struct AuthQuery {
    74→    pub token: Option<String>,
    75→}
    76→
    77→/// Dev Bridge server state
    78→pub struct DevBridgeState {
    79→    /// Auth token (generated at startup)
    80→    pub token: String,
    81→    /// PTY manager reference
    82→    pub pty_manager: Arc<PtyManager>,
    83→    /// Event broadcaster
    84→    pub event_tx: broadcast::Sender<RpcEvent>,
    85→    /// Connected clients count
    86→    pub clients: Mutex<u32>,
    87→}
    88→
    89→impl DevBridgeState {
    90→    pub fn new(pty_manager: Arc<PtyManager>) -> Self {
    91→        let (event_tx, _) = broadcast::channel(1024);
    92→
    93→        // Generate random token
    94→        let token: String = (0..32)
    95→            .map(|_| {
    96→                let idx = rand::random::<u8>() % 62;
    97→                let c = if idx < 10 {
    98→                    (b'0' + idx) as char
    99→                } else if idx < 36 {
   100→                    (b'A' + idx - 10) as char
   101→                } else {
   102→                    (b'a' + idx - 36) as char
   103→                };
   104→                c
   105→            })
   106→            .collect();
   107→
   108→        Self {
   109→            token,
   110→            pty_manager,
   111→            event_tx,
   112→            clients: Mutex::new(0),
   113→        }
   114→    }
   115→
   116→    /// Broadcast an event to all connected clients
   117→    pub fn broadcast(&self, event: RpcEvent) {
   118→        let _ = self.event_tx.send(event);
   119→    }
   120→}
   121→
   122→/// Start the dev bridge server
   123→///
   124→/// Returns the auth token and a handle to the server task
   125→pub async fn start_dev_bridge(
   126→    pty_manager: Arc<PtyManager>,
   127→    port: Option<u16>,
   128→) -> (String, tokio::task::JoinHandle<()>) {
   129→    let port = port.unwrap_or(DEFAULT_PORT);
   130→    let state = Arc::new(DevBridgeState::new(pty_manager));
   131→    let token = state.token.clone();
   132→
   133→    let cors = CorsLayer::new()
   134→        .allow_origin(Any)
   135→        .allow_methods(Any)
   136→        .allow_headers(Any);
   137→
   138→    let app = Router::new()
   139→        .route("/health", get(health_check))
   140→        .route("/ws", get(ws_handler))
   141→        .layer(cors)
   142→        .with_state(state);
   143→
   144→    let addr = format!("127.0.0.1:{}", port);
   145→
   146→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   147→    println!("🌉 DEV BRIDGE ACTIVE (debug mode only)");
   148→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   149→    println!("   Address: http://{}", addr);
   150→    println!("   Token:   {}", token);
   151→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   152→
   153→    // Write token to file for frontend to read
   154→    let token_path = std::env::temp_dir().join("hq-dev-bridge-token");
   155→    if let Err(e) = std::fs::write(&token_path, &token) {
   156→        eprintln!("Warning: Could not write token file: {}", e);
   157→    } else {
   158→        println!("   Token file: {:?}", token_path);
   159→    }
   160→
   161→    let listener = tokio::net::TcpListener::bind(&addr)
   162→        .await
   163→        .expect("Failed to bind dev bridge server");
   164→
   165→    let handle = tokio::spawn(async move {
   166→        axum::serve(listener, app).await.unwrap();
   167→    });
   168→
   169→    (token, handle)
   170→}
   171→
   172→/// Health check endpoint
   173→async fn health_check() -> &'static str {
   174→    "HQ Dev Bridge OK"
   175→}
   176→
   177→/// WebSocket handler with auth
   178→async fn ws_handler(
   179→    ws: WebSocketUpgrade,
   180→    Query(query): Query<AuthQuery>,
   181→    State(state): State<Arc<DevBridgeState>>,
   182→) -> Response {
   183→    // Validate token
   184→    match query.token {
   185→        Some(token) if token == state.token => {
   186→            ws.on_upgrade(move |socket| handle_socket(socket, state))
   187→        }
   188→        _ => (StatusCode::UNAUTHORIZED, "Invalid or missing token").into_response(),
   189→    }
   190→}
   191→
   192→/// Handle WebSocket connection
   193→async fn handle_socket(socket: WebSocket, state: Arc<DevBridgeState>) {
   194→    let (mut sender, mut receiver) = socket.split();
   195→
   196→    // Increment client count
   197→    {
   198→        let mut clients = state.clients.lock();
   199→        *clients += 1;
   200→        println!("Dev Bridge: Client connected (total: {})", *clients);
   201→    }
   202→
   203→    // Subscribe to events
   204→    let mut event_rx = state.event_tx.subscribe();
   205→
   206→    // Clone state for command handler
   207→    let state_cmd = state.clone();
   208→
   209→    // Spawn task to forward events to client
   210→    let send_task = tokio::spawn(async move {
   211→        while let Ok(event) = event_rx.recv().await {
   212→            let msg = serde_json::to_string(&event).unwrap();
   213→            if sender.send(Message::Text(msg.into())).await.is_err() {
   214→                break;
   215→            }
   216→        }
   217→    });
   218→
   219→    // Handle incoming commands
   220→    let recv_task = async {
   221→        while let Some(Ok(msg)) = receiver.next().await {
   222→            if let Message::Text(text) = msg {
   223→                let response = handle_command(&text, &state_cmd).await;
   224→
   225→                // Broadcast the response as an event (sender is moved to send_task)
   226→                state_cmd.broadcast(RpcEvent {
   227→                    event: "rpc-response".to_string(),
   228→                    payload: serde_json::to_value(&response).unwrap(),
   229→                });
   230→            }
   231→        }
   232→    };
   233→
   234→    recv_task.await;
   235→    send_task.abort();
   236→
   237→    // Decrement client count
   238→    {
   239→        let mut clients = state.clients.lock();
   240→        *clients -= 1;
   241→        println!("Dev Bridge: Client disconnected (total: {})", *clients);
   242→    }
   243→}
   244→
   245→/// Handle RPC command
   246→async fn handle_command(text: &str, state: &DevBridgeState) -> RpcResponse {
   247→    let request: RpcRequest = match serde_json::from_str(text) {
   248→        Ok(req) => req,
   249→        Err(e) => {
   250→            return RpcResponse {
   251→                id: "unknown".to_string(),
   252→                success: false,
   253→                result: None,
   254→                error: Some(format!("Invalid JSON: {}", e)),
   255→            };
   256→        }
   257→    };
   258→
   259→    let result = execute_command(&request.cmd, &request.args, state).await;
   260→
   261→    match result {
   262→        Ok(value) => RpcResponse {
   263→            id: request.id,
   264→            success: true,
   265→            result: Some(value),
   266→            error: None,
   267→        },
   268→        Err(e) => RpcResponse {
   269→            id: request.id,
   270→            success: false,
   271→            result: None,
   272→            error: Some(e),
   273→        },
   274→    }
   275→}
   276→
   277→/// Execute a command and return result
   278→async fn execute_command(
   279→    cmd: &str,
   280→    args: &serde_json::Value,
   281→    state: &DevBridgeState,
   282→) -> Result<serde_json::Value, String> {
   283→    match cmd {
   284→        "pty_spawn" => {
   285→            let cmd_str = args["cmd"].as_str().ok_or("Missing 'cmd' argument")?;
   286→            let args_vec: Vec<String> = args["args"]
   287→                .as_array()
   288→                .map(|arr| {
   289→                    arr.iter()
   290→                        .filter_map(|v| v.as_str().map(String::from))
   291→                        .collect()
   292→                })
   293→                .unwrap_or_default();
   294→            let cwd = args["cwd"]
   295→                .as_str()
   296→                .unwrap_or(".")
   297→                .to_string();
   298→            let rows = args["rows"].as_u64().unwrap_or(24) as u16;
   299→            let cols = args["cols"].as_u64().unwrap_or(80) as u16;
   300→
   301→            // Spawn process and set up event forwarding
   302→            let info = spawn_with_events(
   303→                state,
   304→                cmd_str.to_string(),
   305→                args_vec,
   306→                cwd,
   307→                rows,
   308→                cols,
   309→            )?;
   310→
   311→            serde_json::to_value(&info).map_err(|e| e.to_string())
   312→        }
   313→
   314→        "pty_write" => {
   315→            let id = args["id"].as_str().ok_or("Missing 'id' argument")?;
   316→            let data = args["data"].as_str().ok_or("Missing 'data' argument")?;
   317→            state.pty_manager.write(id, data)?;
   318→            Ok(serde_json::Value::Null)
   319→        }
   320→
   321→        "pty_resize" => {
   322→            let id = args["id"].as_str().ok_or("Missing 'id' argument")?;
   323→            let rows = args["rows"].as_u64().ok_or("Missing 'rows' argument")? as u16;
   324→            let cols = args["cols"].as_u64().ok_or("Missing 'cols' argument")? as u16;
   325→            state.pty_manager.resize(id, rows, cols)?;
   326→            Ok(serde_json::Value::Null)
   327→        }
   328→
   329→        "pty_kill" => {
   330→            let id = args["id"].as_str().ok_or("Missing 'id' argument")?;
   331→            state.pty_manager.kill(id)?;
   332→            Ok(serde_json::Value::Null)
   333→        }
   334→
   335→        "pty_list" => {
   336→            let list = state.pty_manager.list();
   337→            serde_json::to_value(&list).map_err(|e| e.to_string())
   338→        }
   339→
   340→        "pty_get" => {
   341→            let id = args["id"].as_str().ok_or("Missing 'id' argument")?;
   342→            let info = state.pty_manager.get(id);
   343→            serde_json::to_value(&info).map_err(|e| e.to_string())
   344→        }
   345→
   346→        "greet" => {
   347→            let name = args["name"].as_str().unwrap_or("World");
   348→            Ok(serde_json::Value::String(format!(
   349→                "Hello, {}! You've been greeted from Dev Bridge!",
   350→                name
   351→            )))
   352→        }
   353→
   354→        _ => Err(format!("Unknown command: {}", cmd)),
   355→    }
   356→}
   357→
   358→/// Spawn PTY process with event forwarding
   359→fn spawn_with_events(
   360→    state: &DevBridgeState,
   361→    cmd: String,
   362→    args: Vec<String>,
   363→    cwd: String,
   364→    rows: u16,
   365→    cols: u16,
   366→) -> Result<ProcessInfo, String> {
   367→    use portable_pty::{native_pty_system, CommandBuilder, PtySize};
   368→
   369→    let pty_system = native_pty_system();
   370→
   371→    let size = PtySize {
   372→        rows,
   373→        cols,
   374→        pixel_width: 0,
   375→        pixel_height: 0,
   376→    };
   377→
   378→    let pair = pty_system
   379→        .openpty(size)
   380→        .map_err(|e| format!("Failed to open pty: {}", e))?;
   381→
   382→    let mut cmd_builder = CommandBuilder::new(&cmd);
   383→    for arg in &args {
   384→        cmd_builder.arg(arg);
   385→    }
   386→    cmd_builder.cwd(&cwd);
   387→
   388→    let _child = pair
   389→        .slave
   390→        .spawn_command(cmd_builder)
   391→        .map_err(|e| format!("Failed to spawn command: {}", e))?;
   392→
   393→    let id = uuid::Uuid::new_v4().to_string();
   394→
   395→    let info = ProcessInfo {
   396→        id: id.clone(),
   397→        cmd: cmd.clone(),
   398→        cwd: cwd.clone(),
   399→        rows,
   400→        cols,
   401→        running: true,
   402→    };
   403→
   404→    // Get reader for streaming output
   405→    let reader = pair
   406→        .master
   407→        .try_clone_reader()
   408→        .map_err(|e| format!("Failed to clone reader: {}", e))?;
   409→
   410→    // Get writer for sending input (will be needed for pty_write in future)
   411→    let _writer = pair
   412→        .master
   413→        .take_writer()
   414→        .map_err(|e| format!("Failed to take writer: {}", e))?;
   415→
   416→    // Store in manager (we need to modify PtyManager to expose internal storage)
   417→    // For now, we'll create a simple internal tracking
   418→
   419→    // Spawn reader thread for event broadcasting
   420→    let process_id = id.clone();
   421→    let event_tx = state.event_tx.clone();
   422→
   423→    std::thread::spawn(move || {
   424→        read_and_broadcast(reader, process_id, event_tx);
   425→    });
   426→
   427→    Ok(info)
   428→}
   429→
   430→/// Read PTY output and broadcast as events
   431→fn read_and_broadcast(
   432→    mut reader: Box<dyn std::io::Read + Send>,
   433→    process_id: String,
   434→    event_tx: broadcast::Sender<RpcEvent>,
   435→) {
   436→    let mut buf = [0u8; 4096];
