```typescript
import { useCallback, useEffect, useState } from 'react';
import {
  Card,
  CardBody,
  CardTitle,
  CardHeader,
  Label,
  Flex,
  FlexItem,
  Progress,
  ProgressSize,
  ProgressMeasureLocation,
  Divider,
  DescriptionList,
  DescriptionListGroup,
  DescriptionListTerm,
  DescriptionListDescription,
  Skeleton,
  Icon,
} from '@patternfly/react-core';
import {
  CheckCircleIcon,
  ClockIcon,
  CodeBranchIcon,
} from '@patternfly/react-icons';
import type { Feature } from '../state/store';
import { harnessReadProgress, harnessGetLastCommit, GitCommit } from '../lib/rpc';

export interface ProgressCardProps {
  projectPath: string;
  features: Feature[];
  activeFeatureId?: string | null;
}

export function ProgressCard({ projectPath, features, activeFeatureId }: ProgressCardProps) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastCommit, setLastCommit] = useState<GitCommit | null>(null);
  const [sessionInfo, setSessionInfo] = useState<string>('');

  // Computed stats
  const total = features.length;
  const completed = features.filter((f) => f.passes).length;
  const percent = total > 0 ? Math.round((completed / total) * 100) : 0;

  // Find active feature
  const activeFeature = features.find((f) => f.id === activeFeatureId);

  // Load harness data on mount
  useEffect(() => {
    async function loadData() {
      setLoading(true);
      setError(null);
      try {
        const [progressContent, commit] = await Promise.all([
          harnessReadProgress(projectPath + '/.harness/progress.txt').catch(() => ''),
          harnessGetLastCommit(projectPath).catch(() => null),
        ]);

        // Extract last session info from progress.txt
        const sessions = progressContent.match(/SESSION: .+/g) || [];
        setSessionInfo(sessions[sessions.length - 1] || 'No session data');
        setLastCommit(commit);
      } catch (e) {
        setError(e instanceof Error ? e.message : 'Failed to load harness data');
      } finally {
        setLoading(false);
      }
    }

    if (projectPath) {
      loadData();
    }
  }, [projectPath]);

  return (
    <Card isCompact>
      <CardHeader>
        <CardTitle>Harness Progress</CardTitle>
      </CardHeader>
      <CardBody>
        {loading ? (
          <Skeleton height="100px" />
        ) : error ? (
          <Label color="red">{error}</Label>
        ) : (
          <Flex direction={{ default: 'column' }} spaceItems={{ default: 'spaceItemsMd' }}>
            {/* Progress bar */}
            <FlexItem>
              <Progress
                value={percent}
                title="Features"
                label={`${completed}/${total}`}
                size={ProgressSize.lg}
                measureLocation={ProgressMeasureLocation.outside}
              />
            </FlexItem>

            <Divider />

            {/* Session and commit info */}
            <FlexItem>
              <DescriptionList isHorizontal isCompact>
                <DescriptionListGroup>
                  <DescriptionListTerm>
                    <Icon><ClockIcon /></Icon> Session
                  </DescriptionListTerm>
                  <DescriptionListDescription>
                    {sessionInfo}
                  </DescriptionListDescription>
                </DescriptionListGroup>

                {lastCommit && (
                  <DescriptionListGroup>
                    <DescriptionListTerm>
                      <Icon><CodeBranchIcon /></Icon> Last Commit
                    </DescriptionListTerm>
                    <DescriptionListDescription>
                      <Label color="blue" isCompact>{lastCommit.hash.substring(0, 7)}</Label>
                      {' '}{lastCommit.message}
                    </DescriptionListDescription>
                  </DescriptionListGroup>
                )}

                {activeFeature && (
                  <DescriptionListGroup>
                    <DescriptionListTerm>
                      <Icon status={activeFeature.passes ? 'success' : 'warning'}>
                        <CheckCircleIcon />
                      </Icon> Active
                    </DescriptionListTerm>
                    <DescriptionListDescription>
                      <Label color={activeFeature.passes ? 'green' : 'yellow'} isCompact>
                        {activeFeature.id}
                      </Label>
                      {' '}{activeFeature.description.split(' - ')[0]}
                    </DescriptionListDescription>
                  </DescriptionListGroup>
                )}
              </DescriptionList>
            </FlexItem>
          </Flex>
        )}
      </CardBody>
    </Card>
  );
}

export default ProgressCard;
```

